-- Import remaining Mailchimp contacts for Maple Park Farm tenant (batch 2)

ON CONFLICT (tenant_id, email) DO UPDATE SET
  first_name = COALESCE(EXCLUDED.first_name, crm_customers.first_name),
  last_name = COALESCE(EXCLUDED.last_name, crm_customers.last_name),
  phone = COALESCE(EXCLUDED.phone, crm_customers.phone),
  timezone = COALESCE(EXCLUDED.timezone, crm_customers.timezone),
  email_opt_in = COALESCE(EXCLUDED.email_opt_in, crm_customers.email_opt_in),
  email_opt_in_at = COALESCE(crm_customers.email_opt_in_at, EXCLUDED.email_opt_in_at),
  tags = COALESCE(EXCLUDED.tags, crm_customers.tags),
  updated_at = NOW();